import{_ as t,a,b as o,c as d,d as p,e as r}from"./chunks/查询额度成功.BKueuYqe.js";import{_ as s,o as n,c as l,a2 as i}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"افزودن Dropbox Channel","description":"","frontmatter":{},"headers":[],"relativePath":"fa/upload/dropbox.md","filePath":"fa/upload/dropbox.md","lastUpdated":1781962217000}'),c={name:"fa/upload/dropbox.md"};function h(b,e,u,m,f,g){return n(),l("div",null,[...e[0]||(e[0]=[i('<h1 id="افزودن-dropbox-channel" tabindex="-1">افزودن Dropbox Channel <a class="header-anchor" href="#افزودن-dropbox-channel" aria-label="Permalink to &quot;افزودن Dropbox Channel&quot;">​</a></h1><h2 id="ابتدا-چه-چیزهایی-لازم-است" tabindex="-1">ابتدا چه چیزهایی لازم است <a class="header-anchor" href="#ابتدا-چه-چیزهایی-لازم-است" aria-label="Permalink to &quot;ابتدا چه چیزهایی لازم است&quot;">​</a></h2><table tabindex="0"><thead><tr><th>مورد</th><th>چرا لازم است</th></tr></thead><tbody><tr><td>Dropbox account</td><td>برای sign in و authorize کردن app</td></tr><tr><td>Dropbox app</td><td>برای ساخت <code>App Key</code> و <code>App Secret</code></td></tr><tr><td>دامنه ImgBed شما</td><td>برای OAuth redirect URI</td></tr><tr><td>فضای Dropbox در دسترس</td><td>به‌عنوان محل واقعی ذخیره files</td></tr></tbody></table><h2 id="مراحل-setup" tabindex="-1">مراحل setup <a class="header-anchor" href="#مراحل-setup" aria-label="Permalink to &quot;مراحل setup&quot;">​</a></h2><h3 id="step-1-ساخت-dropbox-app" tabindex="-1">Step 1: ساخت Dropbox App <a class="header-anchor" href="#step-1-ساخت-dropbox-app" aria-label="Permalink to &quot;Step 1: ساخت Dropbox App&quot;">​</a></h3><ol><li>Dropbox App Console را باز کنید:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://www.dropbox.com/developers/apps</span></span></code></pre></div><ol start="2"><li>یک app جدید بسازید.</li><li>برای access type انتخاب کنید:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>App folder</span></span></code></pre></div><ol start="4"><li>یک نام قابل‌تشخیص برای app بگذارید، مثل <code>imgbed-app</code>.</li><li>بعد از ساخت، app details page را باز کنید.</li></ol><p>access type پیشنهادی:</p><table tabindex="0"><thead><tr><th>Access Type</th><th>Recommendation</th></tr></thead><tbody><tr><td><code>App folder</code></td><td>Recommended. با نحوه ذخیره files در ImgBed هماهنگ است.</td></tr><tr><td><code>Full Dropbox</code></td><td>توصیه نمی‌شود. ImgBed به access کامل account نیاز ندارد.</td></tr></tbody></table><p><img src="'+t+'" alt="Create Dropbox app" loading="lazy"></p><h3 id="step-2-افزودن-redirect-uri" tabindex="-1">Step 2: افزودن Redirect URI <a class="header-anchor" href="#step-2-افزودن-redirect-uri" aria-label="Permalink to &quot;Step 2: افزودن Redirect URI&quot;">​</a></h3><p>در app details page مربوط به Dropbox، تنظیمات OAuth یا Redirect URI را پیدا کنید و اضافه کنید:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/dropbox/callback</span></span></code></pre></div><p>اگر admin panel را از چند domain استفاده می‌کنید، برای هر کدام callback URL متناظر را اضافه کنید.</p><p><img src="'+a+'" alt="Configure redirect URI" loading="lazy"></p><h3 id="step-3-configure-کردن-app-permissions" tabindex="-1">Step 3: Configure کردن App Permissions <a class="header-anchor" href="#step-3-configure-کردن-app-permissions" aria-label="Permalink to &quot;Step 3: Configure کردن App Permissions&quot;">​</a></h3><p>tab <code>Permissions</code> را باز کنید و حداقل این scopes را enable کنید:</p><table tabindex="0"><thead><tr><th>Scope</th><th>Required</th><th>Purpose</th></tr></thead><tbody><tr><td><code>account_info.read</code></td><td>Required</td><td>خواندن account و quota information</td></tr><tr><td><code>files.metadata.read</code></td><td>Required</td><td>خواندن file و folder metadata برای path checks</td></tr><tr><td><code>files.metadata.write</code></td><td>Required</td><td>ساخت folders و نوشتن metadata</td></tr><tr><td><code>files.content.write</code></td><td>Required</td><td>upload files. نبودن این scope باعث <code>required scope &#39;files.content.write&#39;</code> می‌شود.</td></tr><tr><td><code>files.content.read</code></td><td>Recommended</td><td>اجازه download، preview و temporary file links</td></tr></tbody></table><p>پس از انتخاب scopes، پایین page روی <code>Submit</code> بزنید.</p><p><img src="'+o+'" alt="Add permissions" loading="lazy"></p><p>Important:</p><table tabindex="0"><thead><tr><th>Situation</th><th>What To Do</th></tr></thead><tbody><tr><td>scopes را تغییر دادید</td><td>token authorization flow را دوباره اجرا کنید و <code>Refresh Token</code> جدید بگیرید.</td></tr><tr><td>reauthorize نکردید</td><td>token قدیمی permissions جدید را نمی‌گیرد، پس uploads ممکن است همچنان fail شوند.</td></tr></tbody></table><h3 id="step-4-copy-کردن-app-credentials" tabindex="-1">Step 4: Copy کردن App Credentials <a class="header-anchor" href="#step-4-copy-کردن-app-credentials" aria-label="Permalink to &quot;Step 4: Copy کردن App Credentials&quot;">​</a></h3><p>این دو مقدار را از Dropbox app page ذخیره کنید:</p><table tabindex="0"><thead><tr><th>Dropbox Field</th><th>ImgBed Field</th></tr></thead><tbody><tr><td><code>App key</code></td><td><code>App Key</code></td></tr><tr><td><code>App secret</code></td><td><code>App Secret</code></td></tr></tbody></table><h3 id="step-5-پر-کردن-dropbox-channel" tabindex="-1">Step 5: پر کردن Dropbox Channel <a class="header-anchor" href="#step-5-پر-کردن-dropbox-channel" aria-label="Permalink to &quot;Step 5: پر کردن Dropbox Channel&quot;">​</a></h3><p>در Upload Settings، <code>Dropbox</code> را انتخاب کنید و پر کنید:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>What To Enter</th></tr></thead><tbody><tr><td>Channel name</td><td>نام قابل‌تشخیص، مثل <code>Main Dropbox</code></td></tr><tr><td>App Key</td><td>Dropbox <code>App key</code></td></tr><tr><td>App Secret</td><td>Dropbox <code>App secret</code></td></tr><tr><td>Refresh Token</td><td>فعلاً خالی بگذارید</td></tr><tr><td>Root directory</td><td>اختیاری. پیش‌فرض <code>imgbed</code>.</td></tr><tr><td>Note</td><td>اختیاری</td></tr></tbody></table><p><img src="'+d+'" alt="Get token" loading="lazy"></p><h3 id="step-6-گرفتن-refresh-token" tabindex="-1">Step 6: گرفتن Refresh Token <a class="header-anchor" href="#step-6-گرفتن-refresh-token" aria-label="Permalink to &quot;Step 6: گرفتن Refresh Token&quot;">​</a></h3><ol><li>در ImgBed، <code>Get Token</code> را بزنید.</li><li>وارد Dropbox account موردنظر شوید.</li><li>authorization prompt را approve کنید.</li><li>callback page یک <code>Refresh Token</code> نشان می‌دهد.</li><li>آن را copy کنید.</li><li>به ImgBed برگردید و داخل <code>Refresh Token</code> paste کنید.</li></ol><p><img src="'+p+'" alt="Copy token" loading="lazy"></p><h2 id="روش-بررسی" tabindex="-1">روش بررسی <a class="header-anchor" href="#روش-بررسی" aria-label="Permalink to &quot;روش بررسی&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>Expected Result</th></tr></thead><tbody><tr><td>Channel card</td><td>پس از Save، Dropbox channel دیده شود.</td></tr><tr><td>Channel switch</td><td>channel قابل enable باشد.</td></tr><tr><td>Token saved</td><td>detail page نشان دهد <code>Refresh Token</code> ذخیره شده است.</td></tr><tr><td>Upload test</td><td>test image در Dropbox app folder دیده شود.</td></tr></tbody></table><p>اگر quota limits enabled است، quota query را بزنید. پس از query موفق، channel card مقدار used space، total space و last update time را نشان می‌دهد.</p><p><img src="'+r+`" alt="Quota query success" loading="lazy"></p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Problem</th><th>Fix</th></tr></thead><tbody><tr><td>ImgBed می‌گوید configuration incomplete است</td><td>بررسی کنید <code>App Key</code>، <code>App Secret</code> و <code>Refresh Token</code> همگی پر شده باشند.</td></tr><tr><td>Authorization موفق است ولی <code>Refresh Token</code> دیده نمی‌شود</td><td>دوباره <code>Get Token</code> را بزنید و مطمئن شوید offline authorization flow استفاده می‌شود.</td></tr><tr><td>Upload با <code>required scope &#39;files.content.write&#39;</code> fail می‌شود</td><td><code>files.content.write</code> را enable کنید، <code>Submit</code> را بزنید، سپس <code>Refresh Token</code> جدید بگیرید.</td></tr><tr><td>Callback fail می‌شود</td><td>مطمئن شوید redirect URI برابر <code>https://your-domain.com/api/oauth/dropbox/callback</code> است.</td></tr><tr><td>Files پیدا نمی‌شوند</td><td>مطمئن شوید Dropbox app با mode <code>App folder</code> ساخته شده است.</td></tr></tbody></table><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Dropbox App Console را باز کنید</span></span>
<span class="line"><span>-&gt; app بسازید</span></span>
<span class="line"><span>-&gt; App folder access را انتخاب کنید</span></span>
<span class="line"><span>-&gt; https://your-domain.com/api/oauth/dropbox/callback را اضافه کنید</span></span>
<span class="line"><span>-&gt; account_info.read / files.metadata.read / files.metadata.write / files.content.write را enable کنید</span></span>
<span class="line"><span>-&gt; در صورت نیاز files.content.read را هم enable کنید</span></span>
<span class="line"><span>-&gt; Submit</span></span>
<span class="line"><span>-&gt; App Key و App Secret را copy کنید</span></span>
<span class="line"><span>-&gt; در ImgBed وارد کنید</span></span>
<span class="line"><span>-&gt; Get Token را بزنید</span></span>
<span class="line"><span>-&gt; Refresh Token را از callback page copy کنید</span></span>
<span class="line"><span>-&gt; در ImgBed paste و save کنید</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Dropbox App Console: <a href="https://www.dropbox.com/developers/apps" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/apps</a></li><li>Dropbox OAuth Guide: <a href="https://developers.dropbox.com/oauth-guide" target="_blank" rel="noreferrer">https://developers.dropbox.com/oauth-guide</a></li><li>Dropbox Developer Guide: <a href="https://www.dropbox.com/developers/reference/developer-guide" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/reference/developer-guide</a></li></ol>`,45)])])}const q=s(c,[["render",h]]);export{y as __pageData,q as default};
